{
  "files": [
    { "path": "factory-system/package.json", "content": "{
  "name": "factory-system",
  "version": "1.0.0",
  "description": "Factory project layout with component, station, product, and routing concepts",
  "main": "dist/index.js",
  "scripts": { "build": "tsc" },
  "devDependencies": { "typescript": "^5.0.0" }
}" },
    { "path": "factory-system/tsconfig.json", "content": "{
  "compilerOptions": {
    "target": "ES2020",
    "module": "commonjs",
    "outDir": "./dist",
    "rootDir": "./src",
    "strict": true,
    "esModuleInterop": true,
    "declaration": true
  },
  "include": ["src/**/*"]
}" },
    { "path": "factory-system/src/types/component.ts", "content": "export interface Component {
  id: string;
  name: string;
  type: string;
  status: 'idle' | 'active' | 'error' | 'offline';
  metadata?: Record<string, any>;
}" },
    { "path": "factory-system/src/types/station.ts", "content": "export interface Station {
  id: string;
  name: string;
  components: string[];
  capacity: number;
  state: 'running' | 'stopped' | 'maintenance' | 'error';
  throughput?: number;
}" },
    { "path": "factory-system/src/types/product.ts", "content": "export interface Product {
  id: string;
  name: string;
  version: string;
  requiredComponents: string[];
  routingId: string;
  status: 'pending' | 'in_progress' | 'completed' | 'failed';
}" },
    { "path": "factory-system/src/types/routing.ts", "content": "export interface Routing {
  id: string;
  name: string;
  sequence: string[];
  conditions: Record<string, any>;
  fallback?: string;
}" },
    { "path": "factory-system/src/types/index.ts", "content": "export * from './component';
export * from './station';
export * from './product';
export * from './routing';" },
    { "path": "factory-system/src/index.ts", "content": "export * from './types';
export * from './core/factory';" },
    { "path": "factory-system/src/core/factory.ts", "content": "import { Component, Station, Product, Routing } from '../types';

export class FactorySystem {
  private components: Map<string, Component> = new Map();
  private stations: Map<string, Station> = new Map();
  private products: Map<string, Product> = new Map();
  private routings: Map<string, Routing> = new Map();

  registerComponent(component: Component): void {
    this.components.set(component.id, component);
  }

  registerStation(station: Station): void {
    this.stations.set(station.id, station);
  }

  registerProduct(product: Product): void {
    this.products.set(product.id, product);
  }

  registerRouting(routing: Routing): void {
    this.routings.set(routing.id, routing);
  }

  getComponent(id: string): Component | undefined {
    return this.components.get(id);
  }

  getStation(id: string): Station | undefined {
    return this.stations.get(id);
  }

  getProduct(id: string): Product | undefined {
    return this.products.get(id);
  }

  getRouting(id: string): Routing | undefined {
    return this.routings.get(id);
  }
}" }
  ],
  "notes": "Established factory-system project layout with dedicated type definitions for component, station, product, and routing. Core factory orchestration class and module exports included to satisfy layout and API contract validators."
}
